import{toBinary}from"../../util/input.js";const execFlags=new Set(["-exec","-execdir"]),execTerminators=new Set([";","\\;","+"]);export const resolve=(e,t,{fromArgs:r})=>{const n=t.findIndex(e=>execFlags.has(e));if(n>=0){const o=[];for(let e=n+1;e<t.length;e++){const r=t[e];if(execTerminators.has(r))break;"{}"!==r&&o.push(r)}if(o.length>0)return[toBinary(e),...r(o)]}return[toBinary(e)]};